import { IconEyePlus, IconSparkles } from "@tabler/icons-react";
import { useMutation, useQuery, useQueryClient } from "@tanstack/react-query";
import { createFileRoute, Link, useNavigate } from "@tanstack/react-router";
import { Link2, Pencil, Plus, Trash2 } from "lucide-react";
import { useState } from "react";
import { z } from "zod";

import type { ClientItem } from "@/components/client-list-view";
import { ClientListView } from "@/components/client-list-view";
import {
  ContextMenu,
  ContextMenuContent,
  ContextMenuItem,
  ContextMenuSeparator,
  ContextMenuTrigger,
} from "@/components/ui/context-menu";
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
} from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Button } from "@/components/ui/button";
import { cn } from "@/lib/utils";
import { rpc } from "@/rpc/client";

const searchSchema = z.object({
  view: z.string().default("clients-active"),
});

export const Route = createFileRoute("/(protected)/(app)/clients/")({
  component: ClientsPage,
  validateSearch: searchSchema,
});

type FilterView = {
  createdAt: Date | null;
  display: {
    fields: string[];
    groupBy: string | null;
    orderBy: string;
    orderType: string;
    type: string;
  };
  domain: string;
  id: string;
  isSystemCreated: boolean;
  label: string;
  refine: { field: string; op: string; value: string }[];
  updatedAt: Date | null;
};

const DEFAULT_DISPLAY = {
  fields: [],
  groupBy: null,
  orderBy: "createdAt",
  orderType: "desc",
  type: "table",
} as const;

const DEFAULT_REFINE: { field: string; op: string; value: string }[] = [];

function ClientsPage() {
  const navigate = useNavigate();
  const queryClient = useQueryClient();
  const { view: activeView } = Route.useSearch();

  const [createDialogOpen, setCreateDialogOpen] = useState(false);
  const [newViewLabel, setNewViewLabel] = useState("");

  const [editDialogOpen, setEditDialogOpen] = useState(false);
  const [editingView, setEditingView] = useState<FilterView | null>(null);
  const [editLabel, setEditLabel] = useState("");

  const { data: filterViews } = useQuery(
    rpc.filterView.list.queryOptions({ input: { domain: "clients" } }),
  );

  const views = (filterViews ?? []) as FilterView[];

  const createMutation = useMutation({
    mutationFn: (input: { display: typeof DEFAULT_DISPLAY; domain: string; label: string; refine: typeof DEFAULT_REFINE }) =>
      rpc.filterView.create.call(input),
    onSuccess: (data) => {
      queryClient.invalidateQueries({ queryKey: ["filterView"] });
      setCreateDialogOpen(false);
      setNewViewLabel("");
      if (data?.id) {
        navigate({ search: { view: data.id } });
      }
    },
  });

  const updateMutation = useMutation({
    mutationFn: (input: { id: string; label: string }) =>
      rpc.filterView.update.call(input),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["filterView"] });
      setEditDialogOpen(false);
      setEditingView(null);
      setEditLabel("");
    },
  });

  const deleteMutation = useMutation({
    mutationFn: (input: { id: string }) =>
      rpc.filterView.delete.call(input),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["filterView"] });
      navigate({ search: { view: "clients-active" } });
    },
  });

  function handleCreate() {
    if (!newViewLabel.trim()) return;
    createMutation.mutate({
      display: { ...DEFAULT_DISPLAY },
      domain: "clients",
      label: newViewLabel.trim(),
      refine: [...DEFAULT_REFINE],
    });
  }

  function handleEdit() {
    if (!editingView || !editLabel.trim()) return;
    updateMutation.mutate({ id: editingView.id, label: editLabel.trim() });
  }

  function handleDelete(view: FilterView) {
    deleteMutation.mutate({ id: view.id });
  }

  function handleEditOpen(view: FilterView) {
    setEditingView(view);
    setEditLabel(view.label);
    setEditDialogOpen(true);
  }

  function handleCopyLink(viewId: string) {
    const url = `${window.location.origin}/clients?view=${viewId}`;
    navigator.clipboard.writeText(url);
  }

  return (
    <div className="page-wrap w-full *:px-8">
      <div className="mb-6 flex h-12 items-center border-neutral-300 border-b px-4!">
        <div className="flex flex-row items-center gap-1 px-4">
          {views.map((view) => (
            <FilterViewButton
              isActive={view.id === activeView}
              isSystemCreated={view.isSystemCreated}
              key={view.id}
              label={view.label}
              onCopyLink={() => handleCopyLink(view.id)}
              onDelete={() => handleDelete(view)}
              onEdit={() => handleEditOpen(view)}
              viewId={view.id}
            />
          ))}
          <button
            className="flex size-7 cursor-pointer items-center rounded-full border border-neutral-400 border-dashed opacity-50 hover:opacity-100"
            onClick={() => setCreateDialogOpen(true)}
            title="Create Filter View"
            type="button"
          >
            <IconEyePlus className="mx-auto size-4.5" />
          </button>
        </div>
        <div className="grow" />
        <Button
          className="flex"
          onClick={() => navigate({ to: "/clients/new" })}
        >
          <Plus className="mr-1.5 h-4 w-4" />
          New Client
        </Button>
      </div>

      <ClientListView
        domain="clients"
        onClientClick={(client: ClientItem) =>
          navigate({
            params: { clientId: String(client.id) },
            to: "/clients/$clientId",
          })
        }
      />

      <Dialog onOpenChange={setCreateDialogOpen} open={createDialogOpen}>
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Create Filter View</DialogTitle>
            <DialogDescription>
              Add a new filter view to organize your clients.
            </DialogDescription>
          </DialogHeader>
          <Input
            onChange={(e) => setNewViewLabel(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === "Enter") handleCreate();
            }}
            placeholder="View name"
            value={newViewLabel}
          />
          <DialogFooter>
            <Button
              disabled={!newViewLabel.trim() || createMutation.isPending}
              onClick={handleCreate}
            >
              Create
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      <Dialog
        onOpenChange={(open) => {
          setEditDialogOpen(open);
          if (!open) {
            setEditingView(null);
            setEditLabel("");
          }
        }}
        open={editDialogOpen}
      >
        <DialogContent>
          <DialogHeader>
            <DialogTitle>Edit Filter View</DialogTitle>
            <DialogDescription>
              Update the name of this filter view.
            </DialogDescription>
          </DialogHeader>
          <Input
            onChange={(e) => setEditLabel(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === "Enter") handleEdit();
            }}
            placeholder="View name"
            value={editLabel}
          />
          <DialogFooter>
            <Button
              disabled={!editLabel.trim() || updateMutation.isPending}
              onClick={handleEdit}
            >
              Save
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

function FilterViewButton({
  isActive,
  isSystemCreated,
  label,
  onCopyLink,
  onDelete,
  onEdit,
  viewId,
}: {
  isActive: boolean;
  isSystemCreated: boolean;
  label: string;
  onCopyLink: () => void;
  onDelete: () => void;
  onEdit: () => void;
  viewId: string;
}) {
  return (
    <ContextMenu>
      <ContextMenuTrigger
        className={cn(
          "rounded-full px-3.5 py-1.5 font-medium",
          isActive
            ? "bg-neutral-800 text-white"
            : "text-secondary-foreground hover:bg-neutral-300/80",
        )}
      >
        <Link search={{ view: viewId }} to="/clients">
          {label}
        </Link>
      </ContextMenuTrigger>
      <ContextMenuContent>
        {!isSystemCreated && (
          <>
            <ContextMenuItem onClick={onEdit}>
              <Pencil />
              Edit
            </ContextMenuItem>
            <ContextMenuItem onClick={onDelete} variant="destructive">
              <Trash2 />
              Delete
            </ContextMenuItem>
            <ContextMenuSeparator />
          </>
        )}
        <ContextMenuItem onClick={onCopyLink}>
          <Link2 />
          Copy Link
        </ContextMenuItem>
        <ContextMenuItem>
          <IconSparkles className="size-4" />
          Ask AI
        </ContextMenuItem>
      </ContextMenuContent>
    </ContextMenu>
  );
}

